import{_ as a,o as t,c as n,j as e,a as p,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const A=JSON.parse('{"title":"破天斩空","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/破天斩空 .md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/破天斩空 .md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/4.A级/破天斩空 .md"};function c(d,r,i,b,l,_){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"破天斩空",tabindex:"-1"},[p("破天斩空 "),e("a",{class:"header-anchor",href:"#破天斩空","aria-label":'Permalink to "破天斩空"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌038")])])],-1),o('<h1 id="破天斩空-1" tabindex="-1">破天斩空 <a class="header-anchor" href="#破天斩空-1" aria-label="Permalink to &quot;破天斩空&quot;">​</a></h1><p>IDEA-A-015-『破天斩空』<br> 科技本质<br> A+4000<br> 分类：轻剑<br> 武器伤害：33L<br> 武器特性：【破甲16】【高速15】【8加骰】<br> 伤害类型：物理-挥砍<br> 体积：3<br> 『破天斩空』是一柄通体银蓝的单手长剑，蓝色的金属制护手；那在阳光下可以反射出蓝色弧光的白色剑身中封印着名为『通天羽兽（Ziz）』的异灵（Sprite），剑身长60cm，通长90cm，宽5cm，在其代表风与天的异能的辅助下，武器的重量几乎等于零，挥舞时仿佛不存在质量，这会导致在攻击时很难去把握出力的多少，而『通天羽兽』则会在该过程中进行智能测算并即时调控武器异能出力，令持有者无论以何种力量进行战斗都可以将武装质量调整至绝对顺手的状态，持有该武器会获得3DP全检定加值，加值来源为器械。</p><p>该武器内嵌的异能为『破天斩空（Heaven Broken）』，这是一个来源于一只巨兽而非人类的异能，该武器在制造时完全采用了巨兽的身体素材，通过多种辅助异能压缩能量与质量，从而将足以顶天立地的巨兽浓缩为手中的这一柄轻剑武装，正因如此，该武装的异能在沉寂（Silence）状态下，只有超越寻常武器的高速与破防能力而已，但若主动解放『通天羽兽（Ziz）』的枷锁，就可以从中获得真正的力量。<br> 完全消耗移动动作，你将『破天斩空』举起，立在胸前，口述以下密钥（Keyword）以解锁内置的异能限制器：<br> “我将于末日前献身。”<br> 在确认口令后，『通天羽兽（Ziz）』会进入口令解锁模式，武装的蓝色金属制护手将即刻展开，露出两侧各三条蓝色锁链状能量羽纹，并进行三问播报：<br> “汝为何物？”<br> “汝为何生？”<br> “汝为何死？”</p><p>为了完全解放『通天羽兽』的能力，你需要口述下述密钥进行回答：<br> “吾为主之貌、人之子。”<br> “吾为界定天地界限而生。”<br> “吾为扫荡世间厄敌而死。”</p><p>每回答一句密钥，两侧的蓝色锁链状羽纹就会崩断一根，当三根锁链全部解锁之后，『通天羽兽』将立即进入『完全同频（ALL Accept）』状态，无数的肌肉与骨骼从武装的护手中超越原有质量地挤压而出，这些血肉将立即包裹持有者并在体表创造出一层以『天堂巨兽（Ziz）』的因子组成的银白色生物质甲壳，在肩、肘、领口和腰间这些部位会生长出洁白华丽的羽毛，在阳光下散发出蓝色的反光，头部则是骑士面罩般的银白头盔，为你提供全环境呼吸的能力与黑暗视觉，每个关节位置都有着完美契合肉体的复合关节，这些生物盔甲会包裹并同化原本穿着的重甲装备，基于原有装备基础额外获得12点的天生防御与【封闭5】，额外提供120米移速，你可以随时在后肩的位置生长出任意物种的翅膀作为披风，但如果是非鸟类，会因『通天羽兽』的情绪影响额外承受1点不可豁免的沮丧点数，以此生长而来的披风可以为你提供机动性为完美的飞行移动能力，生长完毕后，从长剑中会生长出三只翅膀，完全包裹住持剑的那只手臂，如遮蔽半身的决斗斗篷，亦如根植寄生的生物攀藤，这些扎根在肉体中的羽状触须会令该武装免疫武器击落。<br> 保持『完全同频（ALL Accept）』状态的时间越久，与『天堂巨兽（Ziz）』的排斥反应就会越强，在该状态下，每个回合结束时，都会使得自己在以『破天斩空』进行攻击时额外获得2点附加成功，至多以此获益三次，相对的，每个回合结束时，自身立即承受1点不可豁免不可吸收的韧性伤害；战斗结束后，或者主动以移动动作结束『完全同频（ALL Accept）』状态后，都将立即承受『完全同频（ALL Accept）』状态开启轮次*1点无法在当前场景豁免的疲乏点数与不可豁免的精神严重伤害。</p><p>特殊的，该武器仅限人类血统使用，任何非人类、构造体、额外生物类型、不视为人类、不具备人貌者不被该武装所承认，仅具有武器的基础特性。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=a(s,[["render",c]]);export{A as __pageData,m as default};
